INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604536N$$, 2026, $$The Orca Extra Large Unmanned Undersea Vehicle (XLUUV) is the Navy's initial Extra Large UUV effort that falls under the UUV Family of Systems. The Orca XLUUV
effort was established to address a Joint Emergent Operational Need (JEON) and is multi-phased accelerated acquisition effort to rapidly deliver capability to the Fleet.
Phase 1 was a competitively sourced design effort. Phase 2 down selected to one of the Phase 1 vendors in FY 2019 for fabrication and testing of the vehicle and
support elements. Testing and delivery of the vehicles and support elements were delayed to FY23-26 due to contractor challenges and supplier issues. The Navy
is working with the OEM to mitigate schedule delays by continuing to execute risk reduction testing and training through the addition of a designated test and training
asset (Vehicle 0) which was delivered in FY24. The Navy is updating facilities at Naval Base Ventura County and Naval Base Kitsap to support testing, training, and
workups, in coordination with large, unmanned surface vessel testing for cost efficiencies. The Navy is also updating facilities at a Forward Operating Base (FOB) to
support future UUV operation in theater. Design and fabrication of a single Hunter payload will be initiated in FY26 with a planned integration to the XLUUVs at the
forwarding operating base. The XLUUV has a modular payload bay, with defined interfaces, to support quick integration with future payloads/sensors. The Orca XLUUV
efforts include integrating potential future payloads and capabilities which will be developed, evaluated, and preliminarily integrated leveraging the Core Technologies
Program Element 0604029N. In addition, the Combat Autonomous Maritime Platform (CAMP) project will conduct competitive Extra Large Unmanned Undersea Vehicle
capability demonstrations leveraging commercial sources and non-developmental prototypes in accordance with FY25 NDAA section 1032. The project will use the
Defense Innovation Unit's (DIU) Commercial Solution Opening (CSO) process, prototyping, and spiral development. Systems will be assessed on vehicle range, payload
capacities, and technical maturity to meet Indo-Pacific Command requirements$$, $$The Orca Extra Large Unmanned Undersea Vehicle (XLUUV) is the Navy's Extra Large UUV effort which is part of the UUV Family of Systems (FoS). The Orca XLUUV
effort was established to address a Joint Emergent Operational Need (JEON). Orca has a modular payload bay, with defined interfaces that current and future payloads
must adhere to for employment from the vehicle. The Orca XLUUV effort will integrate the currently required payload, and additional potential future payloads will be
developed, evaluated, and preliminarily integrated under the Core Technologies Program Element 0604029N. Additional XLUUV technologies/capabilities risk reduction
will occur in parallel, leveraging the competitive Industrial base. In addition, the Combat Autonomous Maritime Platform (CAMP) project will conduct competitive Extra
Large Unmanned Undersea Vehicle capability demonstrations leveraging commercial sources and non-developmental prototypes in accordance with FY25 NDAA
section 1032. The project will use the Defense Innovation Unit's (DIU) Commercial Solution Opening (CSO) process, prototyping, and spiral development. Systems will
be assessed on vehicle range, payload capacities, and technical maturity to meet Indo-Pacific Command requirements.

