INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605516M$$, 2026, $$The Long Range Fires (LRF) program sought to provide Combatant Commanders with the ability to employ an agile, mobile, land-based system, capable of launching
Tomahawk cruise missiles to complement surface and sub-surface launched missiles.

The LRF weapon system consisted of a ROGUE-Fires carrier (same design as the Navy and Marine Corps Expeditionary Ship Interdiction System (NMESIS) carrier),
integrated with a single cell MK-41 vertical launch system launcher (a similar configuration to those employed by the US Navy) for the employment of an encanistered
Tomahawk missile, and Tactical Tomahawk Weapons Control System.$$, $$The LRF program sought to provide Combatant Commanders with the ability to employ an agile, mobile, land-based system, capable of launching Tomahawk cruise
missiles to complement surface and sub-surface launched missiles.

In FY 2025, LRF completed system development and conducted testing concluding that the LRF system was not able to be employed in austere, expeditionary, littoral
environments. As a result, the Marine Corps, in conjunction with the Office of the Secretary of Defense, has terminated the LRF program.

